 true\n}\n\nfunc (i *InMemory) isRegistered(pluginID string) bool {\n\tp, exists := i.plugin(pluginID)\n\n\t// This may have matched based on an alias\n\treturn exists && p.ID == pluginID\n}\n", "numLines": 99, "startLine": 1, "totalLines": 99}}

